//! Auto-generated by the spec-word-compliance workflow for area
//! "Paragraph indentation, spacing, and alignment (precedence/normalization traps)".
//!
//! Each `#[test]` encodes a Word-compliance constraint mined from ISO/IEC 29500,
//! ECMA-376, and the MS-OI29500 implementer notes. A FAILING assertion here
//! encodes a REAL Word-compliance gap in the stemma engine — it is a finding to
//! be traced to its source, NOT something to make pass by weakening the test.
//!
//! METHODOLOGY: stemma round-trips untouched content byte-verbatim, so XML
//! assertions on `reserialize()` of an unedited doc reflect stemma's
//! verbatim-preservation contract (and its serializer's Annex A ordering), NOT
//! Word's render-time normalization. Consumption semantics ("value ignored",
//! "clamped at render") are therefore tested on the READ side (opens-clean,
//! accept/reject text), not on the re-serialized XML.

use std::io::{Read, Write};

use stemma::api::Document;

// ─── Prelude ─────────────────────────────────────────────────────────────────

/// Build a minimal valid `.docx`. `body_xml` is the raw inner body markup
/// (paragraphs/tables/sectPr); it is wrapped in `<w:document><w:body>…</w:body>`.
/// `extra_parts` are additional `(part_path, xml)` entries (e.g. `word/styles.xml`)
/// that also get a `[Content_Types].xml` override.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content type override per extra part, keyed by file extension presence in
    // the part path. For the parts we use here (styles.xml / numbering.xml) we
    // emit the matching WordprocessingML content type.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part, _) in extra_parts {
        let ct = if part.ends_with("styles.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        } else if part.ends_with("numbering.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        } else {
            "application/xml"
        };
        let part_name = if part.starts_with('/') {
            part.to_string()
        } else {
            format!("/{part}")
        };
        overrides.push_str(&format!(
            r#"<Override PartName="{part_name}" ContentType="{ct}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // Document rels: add a relationship for each extra part so the reference
    // resolves (styles/numbering). Type is inferred from the part name.
    let mut doc_rel_entries = String::new();
    for (i, (part, _)) in extra_parts.iter().enumerate() {
        let (rel_type, target) = if part.ends_with("styles.xml") {
            (
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles",
                "styles.xml",
            )
        } else if part.ends_with("numbering.xml") {
            (
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering",
                "numbering.xml",
            )
        } else {
            (
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/unprocessed",
                "unknown.xml",
            )
        };
        doc_rel_entries.push_str(&format!(
            r#"<Relationship Id="rIdX{i}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rel_entries}</Relationships>"#
    );

    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            let part_path = part.trim_start_matches('/');
            zip.start_file(part_path, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a string.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive =
        zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip for document.xml");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut out = String::new();
    file.read_to_string(&mut out)
        .expect("read word/document.xml");
    out
}

/// Parse → serialize(default) → return `word/document.xml`. This reflects
/// stemma's serializer output (Annex A ordering + verbatim passthrough), which
/// is the valid surface for ordering/structural-synthesis assertions only.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize");
    document_xml_of(&out)
}

/// Read accept-all text (trimmed).
fn accept_text(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for accept text");
    doc.read_accepted()
        .expect("read_accepted")
        .to_text()
        .trim()
        .to_string()
}

/// Read reject-all text (trimmed).
#[allow(dead_code)]
fn reject_text(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reject text");
    doc.read_rejected()
        .expect("read_rejected")
        .to_text()
        .trim()
        .to_string()
}

/// Assert `stemma::api::validate` reports no errors (opens clean).
fn assert_opens_clean(bytes: &[u8], msg: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{msg} — validator reported issues: {:?}",
        report.issues
    );
}

// ─── Tests ───────────────────────────────────────────────────────────────────

#[test]
fn jc_medium_kashida_value_domain_opens_clean() {
    let body = r#"<w:p><w:pPr><w:jc w:val="mediumKashida"/></w:pPr><w:r><w:t>Kashida aligned</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "mediumKashida is an enumerated ST_Jc value (ISO 29500-1 §17.18.44, §17.3.1.13); \
         the document is schema-valid and Word opens it without repair",
    );
    assert_eq!(
        accept_text(&b),
        "Kashida aligned",
        "Kashida alignment affects only Arabic kashida joiner glyphs (§17.18.44); \
         read text content must be unchanged"
    );
}

#[test]
fn tab_pos_beyond_word_clamp_range_opens_clean() {
    let body = r#"<w:p><w:pPr><w:tabs><w:tab w:val="left" w:pos="50000"/></w:tabs></w:pPr><w:r><w:t>Tab past Word clamp</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "MS-OI29500 §2.1.61 / ISO 29500-1 §17.3.1.37 / §17.18.81: Word clamps pos at render but \
         ST_SignedTwipsMeasure has no min/max facet, so pos=50000 is schema-valid and Word opens \
         it without repair; validator must report no errors",
    );
    assert_eq!(
        accept_text(&b),
        "Tab past Word clamp",
        "Out-of-range tab stop is layout-only (§17.3.1.37); paragraph text is unaffected"
    );
}

#[test]
fn mirror_indents_in_table_cell_opens_clean() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="4000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="4000" w:type="dxa"/></w:tcPr><w:p><w:pPr><w:mirrorIndents/></w:pPr><w:r><w:t>Cell with mirrorIndents</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p><w:pPr><w:sectPr/></w:pPr></w:p>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "MS-OI29500 §2.1.49 / ISO 29500-1 §17.3.1.18: mirrorIndents is allowed on any paragraph; \
         Word only ignores it at render inside tables, so the file is valid markup and opens \
         without repair; validator must report no errors",
    );
    assert_eq!(
        accept_text(&b),
        "Cell with mirrorIndents",
        "mirrorIndents is layout-only (§17.3.1.18); cell text content is unaffected"
    );
}

#[test]
fn jc_both_justify_opens_clean_text_unchanged() {
    let body = r#"<w:p><w:pPr><w:jc w:val="both"/></w:pPr><w:r><w:t>Justified paragraph text</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "MS-OI29500 §2.1.545 / ISO 29500-1 §17.18.44 / §17.3.1.13: jc=both is a valid ST_Jc value; \
         Word's only deviation is a render-time lowKashida decision, so the file opens without \
         repair; validator must report no errors",
    );
    assert_eq!(
        accept_text(&b),
        "Justified paragraph text",
        "Alignment is layout-only and the lowKashida deviation is render-only (§2.1.545); \
         paragraph text content is unchanged"
    );
}

