#[test]
fn ind_firstline_and_hanging_both_direct_open_clean_word_normalizes_to_hanging() {
    let body = r#"<w:p><w:pPr><w:ind w:left="1440" w:firstLine="720" w:hanging="360"/></w:pPr><w:r><w:t>Both first-line modifiers present.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "CT_Ind defines firstLine and hanging as independent optional attributes (ISO 29500-1 \
         §17.3.1.12 / ECMA-376 Annex A CT_Ind); an ind carrying both is well-formed against the \
         schema, so Word opens it without repair (mutual-exclusivity is a consumption rule, not a \
         well-formedness constraint)",
    );
    assert_eq!(
        accept_text(&b),
        "Both first-line modifiers present.",
        "Indentation is layout-only (§17.3.1.12); the firstLine/hanging conflict must not corrupt \
         content extraction"
    );
    // ORACLE half (not daily-testable): Word opens without repair and, on resave,
    // emits w:ind with hanging only (firstLine dropped, §17.3.1.12).
}

#[test]
fn spacing_before_only_no_line_no_linerule_opens_clean_inherits_line() {
    let body = r#"<w:p><w:pPr><w:spacing w:before="240"/></w:pPr><w:r><w:t>Only before set.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "Every w:spacing attribute is independently optional (ISO 29500-1 §17.3.1.33 / §17.7.2); \
         a spacing element carrying only before is schema-valid and Word opens it without repair",
    );
    assert_eq!(
        accept_text(&b),
        "Only before set.",
        "Spacing is layout-only (§17.3.1.33); the partial spacing element must not break content \
         extraction"
    );
}

#[test]
fn spacing_line_negative_signed_twips_opens_clean() {
    let body = r#"<w:p><w:pPr><w:spacing w:line="-240" w:lineRule="auto"/></w:pPr><w:r><w:t>Negative line spacing</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "line is typed ST_SignedTwipsMeasure (ISO 29500-1 §17.3.1.33 / §17.18.81), so a negative \
         line is in-domain and must validate clean; the validator must not reject it as an \
         out-of-range twips value",
    );
}

#[test]
fn ppr_textalignment_must_follow_jc_ordering() {
    let body = r#"<w:p><w:pPr><w:jc w:val="center"/><w:textAlignment w:val="center"/></w:pPr><w:r><w:t>Ordered pPr children</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "CT_PPr is an Annex A ordered sequence with jc before textAlignment (ISO 29500-1 \
         §17.3.1.13 / §17.3.1.39 / ECMA-376 Annex A CT_PPr); this paragraph emits jc then \
         textAlignment, the correct order, so it must validate clean",
    );
    // xmlRegex translated to a contains check (no regex crate in dev-deps):
    // the original pattern was `<w:jc[^>]*/>\s*<w:textAlignment`. stemma
    // preserves untouched pPr verbatim and emits CT_PPr children in Annex A
    // order, so jc must appear before textAlignment on re-serialize. We assert
    // the jc element's position index precedes the textAlignment element's.
    let xml = reserialize(&b);
    let jc_pos = xml
        .find("<w:jc")
        .expect("re-serialized XML must contain <w:jc");
    let ta_pos = xml
        .find("<w:textAlignment")
        .expect("re-serialized XML must contain <w:textAlignment");
    assert!(
        jc_pos < ta_pos,
        "stemma's serializer must keep CT_PPr children in Annex A order (jc before textAlignment, \
         ECMA-376 Annex A CT_PPr); got jc at {jc_pos}, textAlignment at {ta_pos} in: {xml}"
    );
}

#[test]
fn spacing_linerule_without_line_opens_clean() {
    let body = r#"<w:p><w:pPr><w:spacing w:lineRule="exact"/></w:pPr><w:r><w:t>Lone lineRule</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "line and lineRule are independent optional CT_Spacing attributes (ISO 29500-1 \
         §17.3.1.33 / §17.18.48); a w:spacing with lineRule but no line is schema-valid and must \
         open clean",
    );
    assert_eq!(
        accept_text(&b),
        "Lone lineRule",
        "With no line value specified, single spacing applies (§17.3.1.33); the paragraph text \
         reads unchanged"
    );
}

#[test]
fn spacing_beforelines_negative_decimal_opens_clean() {
    let body = r#"<w:p><w:pPr><w:spacing w:beforeLines="-100"/></w:pPr><w:r><w:t>Negative beforeLines</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "beforeLines is typed ST_DecimalNumber (ISO 29500-1 §17.3.1.33 / §17.18.10), a signed \
         integer domain, so a negative value is legal and must validate clean",
    );
}
